mapper.select:
SELECT opid, building_id, room_id, build_area, is_voting_delegate, account_status
FROM c_owner_property
WHERE uid = #{uid}
  AND tenant_id = #{tenantId}
  AND opid = #{opid}

SELECT EXISTS (
    SELECT 1 FROM c_owner_property
    WHERE tenant_id = #{tenantId}
      AND building_id = #{buildingId}
    UNION ALL
    SELECT 1 FROM c_property_roster
    WHERE tenant_id = #{tenantId}
      AND building_id = #{buildingId}
      AND status = 'ACTIVE'
)

SELECT EXISTS (
    SELECT 1 FROM c_owner_property
    WHERE tenant_id = #{tenantId}
      AND room_id = #{roomId}

      AND building_id = #{buildingId}

    UNION ALL
    SELECT 1 FROM c_property_roster
    WHERE tenant_id = #{tenantId}
      AND room_id = #{roomId}
      AND status = 'ACTIVE'

      AND building_id = #{buildingId}

)

SELECT 
FROM t_repair_work_order
WHERE tenant_id = #{tenantId}
  AND reporter_account_id = #{reporterAccountId}
  AND space_scope = #{spaceScope}
  AND LOWER(title) = LOWER(#{title})
  AND create_time >= #{since}
  AND status NOT IN ('ARCHIVED', 'REJECTED', 'CANCELLED')
  AND (
      (#{roomId,jdbcType=BIGINT} IS NULL AND room_id IS NULL)
      OR room_id = #{roomId,jdbcType=BIGINT}
  )
  AND (
      (#{buildingId,jdbcType=BIGINT} IS NULL AND building_id IS NULL)
      OR building_id = #{buildingId,jdbcType=BIGINT}
  )
ORDER BY create_time DESC
LIMIT 1

SELECT 
FROM t_repair_work_order
WHERE work_order_id = #{workOrderId}

SELECT wo.
FROM t_repair_work_order wo
WHERE wo.work_order_id = #{workOrderId}
  AND wo.tenant_id = #{tenantId}
  AND (
      wo.reporter_account_id = #{accountId}
      OR (
          wo.space_scope = 'PUBLIC'
          AND wo.building_id IN (
              SELECT DISTINCT op.building_id
              FROM c_owner_property op
              WHERE op.uid = #{uid}
                AND op.tenant_id = #{tenantId}
                AND op.account_status = 1
          )
      )
  )

SELECT wo.
FROM t_repair_work_order wo
WHERE wo.tenant_id = #{tenantId}
  AND (
      wo.reporter_account_id = #{accountId}
      OR (
          wo.space_scope = 'PUBLIC'
          AND wo.building_id IN (
              SELECT DISTINCT op.building_id
              FROM c_owner_property op
              WHERE op.uid = #{uid}
                AND op.tenant_id = #{tenantId}
                AND op.account_status = 1
          )
      )
  )
ORDER BY wo.create_time DESC, wo.work_order_id DESC
LIMIT 50

SELECT quote_id, work_order_id, tenant_id, supplier_name, quote_amount, quote_summary,
       attachment_id, attachment_hash, submitted_by_user_id, submitted_by_role_key,
       submitted_by_supplier, supplier_confirmed, supplier_dept_id, quote_invitation_id,
       submission_source, confirmation_status, original_source, original_attachment_hash,
       create_time
FROM t_repair_supplier_quote
WHERE quote_id = #{quoteId}
  AND work_order_id = #{workOrderId}
  AND tenant_id = #{tenantId}

SELECT EXISTS (
    SELECT 1
    FROM t_repair_quote_invitation
    WHERE work_order_id = #{workOrderId}
      AND tenant_id = #{tenantId}
      AND supplier_dept_id = #{supplierDeptId}
      AND status IN ('PENDING', 'SUBMITTED')
)

SELECT COUNT(1)
FROM t_repair_supplier_quote
WHERE work_order_id = #{workOrderId}
  AND tenant_id = #{tenantId}

SELECT COUNT(1)
FROM t_repair_quote_invitation
WHERE work_order_id = #{workOrderId}
  AND tenant_id = #{tenantId}
  AND status <> 'CANCELLED'

SELECT supplier_dept_id
FROM t_supplier_org_profile
WHERE unified_social_credit_code = #{unifiedSocialCreditCode}

