SELECT 
FROM t_supplier_activation_invitation i
JOIN t_supplier_org_profile p ON p.supplier_dept_id = i.supplier_dept_id
WHERE i.supplier_dept_id = #{supplierDeptId}
  AND i.contact_phone = #{contactPhone}
  AND i.status = 'PENDING'
  AND i.expires_at > #{now}
ORDER BY i.create_time DESC
LIMIT 1

