SELECT EXISTS (
    SELECT 1
    FROM t_supplier_tenant_relation
    WHERE relation_id = #{relationId}
      AND tenant_id = #{tenantId}
      AND supplier_dept_id = #{supplierDeptId}
      AND relation_type = 'FRAMEWORK'
      AND status = 'ACTIVE'
      AND (valid_from IS NULL OR valid_from <= CURRENT_DATE)
      AND (valid_until IS NULL OR valid_until >= CURRENT_DATE)
      AND (service_category IS NULL OR service_category = #{serviceCategory})
)

WITH all_rooms AS ( SELECT room_id, build_area FROM c_property_roster WHERE tenant_id = #{tenantId} AND building_id = #{buildingId} AND status = 'ACTIVE' AND room_id IS NOT NULL
AND unit_name = #{unitName}
UNION ALL SELECT op.room_id, op.build_area FROM c_owner_property op WHERE op.tenant_id = #{tenantId} AND op.building_id = #{buildingId} AND op.account_status = 1 AND op.room_id IS NOT NULL AND NOT EXISTS ( SELECT 1 FROM c_property_roster pr WHERE pr.tenant_id = op.tenant_id AND pr.room_id = op.room_id AND pr.status = 'ACTIVE' )
), rooms AS ( SELECT room_id, MAX(build_area) AS build_area FROM all_rooms GROUP BY room_id ) SELECT COUNT(1)::INT AS total_owner_count, COALESCE(SUM(build_area), 0)::NUMERIC(14, 2) AS total_area FROM rooms

WITH all_rooms AS ( SELECT room_id, build_area FROM c_property_roster WHERE tenant_id = #{tenantId} AND building_id = #{buildingId} AND status = 'ACTIVE' AND room_id IS NOT NULL
AND unit_name = #{unitName}
UNION ALL SELECT op.room_id, op.build_area FROM c_owner_property op WHERE op.tenant_id = #{tenantId} AND op.building_id = #{buildingId} AND op.account_status = 1 AND op.room_id IS NOT NULL AND NOT EXISTS ( SELECT 1 FROM c_property_roster pr WHERE pr.tenant_id = op.tenant_id AND pr.room_id = op.room_id AND pr.status = 'ACTIVE' )
) SELECT room_id, MAX(build_area)::NUMERIC(14, 2) AS build_area FROM all_rooms GROUP BY room_id ORDER BY room_id

