SELECT EXISTS (
    SELECT 1 FROM t_repair_acceptance_scope
    WHERE work_order_id = #{workOrderId}
      AND tenant_id = #{tenantId}
      AND room_id = #{roomId}
)

SELECT EXISTS (
    SELECT 1
    FROM t_repair_acceptance_scope scope
    JOIN c_owner_property property
      ON property.tenant_id = scope.tenant_id
     AND property.room_id = scope.room_id
     AND property.account_status = 1
    WHERE scope.work_order_id = #{workOrderId}
      AND scope.tenant_id = #{tenantId}
      AND scope.room_id = #{roomId}
      AND property.uid = #{uid}
)

SELECT DISTINCT scope.room_id
FROM t_repair_acceptance_scope scope
JOIN c_owner_property property
  ON property.tenant_id = scope.tenant_id
 AND property.room_id = scope.room_id
 AND property.account_status = 1
WHERE scope.work_order_id = #{workOrderId}
  AND scope.tenant_id = #{tenantId}
  AND property.uid = #{uid}
ORDER BY scope.room_id

